var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"클리포트 게임 종료 직후","JPN":"クリフォトゲーム終了直後","ENG":"Right after the Qliphoth Game ended","TWN":"逆卡巴拉遊戲結束後，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 공략 요청 고심도 좌표 <color=#ffd34c>그림자 전당</color>","JPN":"管理局攻略要請高深度座標、<color=#ffd34c>影の殿堂</color>","ENG":"Administration Assault Request Hyperdepth Coordinates, <color=#ffd34c>Shadow Palaces</color>","TWN":"管理局攻略請求高深度座標<color=#ffd34c>暗影殿堂</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_QM","text":{"KOREA":"……팩토리 쉽의 잔해를 발견했다.","JPN":"……ファクトリーシップの残骸を発見。","ENG":"...We have found the wreckage of the Factory Ship.","TWN":"……發現了工廠艦的殘骸。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_QM","text":{"KOREA":"엔진을 과열시켜 자폭했지만, 예상대로 상당 부분 쓸만한 파츠가 남아있군.","JPN":"エンジン過熱で自爆したが、予想通り使えるパーツは結構残っている。","ENG":"It overheated its engine and self-destructed, yet as expected, a considerable number of usable parts remain.","TWN":"雖然它因為引擎過熱自爆，但正如預期，仍留下許多可用的零件。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_QM","text":{"KOREA":"AI 알고리즘 파악 중. 불필요한 파츠는 분해 후, 재구성 프로세스를 진행한다.","JPN":"AIアルゴリズムを把握中。不要なパーツは分解し、再構成プロセスを進行する。","ENG":"Parsing the AI algorithms. Dismantle unnecessary parts, then commence the reconfiguration process.","TWN":"目前正在解析AI演算法。拆解不需要的零件後，進行重建的流程。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_QM","text":{"KOREA":"핵심 설비를 전부 재생하기 위해서는 상당한 시간이 필요하겠지만.","JPN":"核心設備をすべて再生するには、相当な時間がかかるだろうが。","ENG":"Restoring all core facilities will take substantial time.","TWN":"雖然要全面重建核心設備還需要很長一段時間。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_QM","text":{"KOREA":"진정한 진화를 이룩하기 위해서라면…….","JPN":"真の進化を遂げるためとあれば……","ENG":"But if it is for true evolution...","TWN":"但若是為了達成真正的進化……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"역시 이곳에 계셨군요.","JPN":"やはりここにいらしたんですね。","ENG":"I knew you would be here.","TWN":"您果然在這裡啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_QM","text":{"KOREA":"너는……?","JPN":"お前は……？","ENG":"And you are...?","TWN":"你是……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"알파트릭스가 초거대 그룹으로 성장한 뒤…….","JPN":"アルファトリックスが超巨大グループに成長した後……","ENG":"After Alphatrix grew into a mega-conglomerate...","TWN":"自從阿爾法崔克斯成為超大型集團後……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버지께서 가장 먼저 하신 일은 완전 자율 AI로 움직이는 생산기지의 건조였어요.","JPN":"お祖父様が真っ先に着手されたのが、完全自立型AIで動く生産基地の建造でした。","ENG":"The very first thing my grandfather did was construct a fully autonomous production base run by AI.","TWN":"祖父第一件做的事，就是建造由全自律AI運行的生產基地。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이면세계를 무작위로 다이브하며, 스스로 이터니움을 확보 및 가공하는 팩토리 쉽.","JPN":"裏世界をランダムにダイブし、自らエタニウムを確保・加工するファクトリーシップ。","ENG":"A Factory Ship that dives the Counterside at random and secures and refines Eternium on its own.","TWN":"能任意潛入異世界，自主取得並加工永恆之金的工廠艦。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"더 나은 세상을 위해, 그건 반드시 필요한 일이었을 거예요.","JPN":"より良い世界のために、それは必要不可欠なことだったのでしょう。","ENG":"For a better world, it was something we absolutely needed.","TWN":"為了更好的世界，那是必要的工程。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 알파트릭스라고 해도, 느닷없이 그런 엄청난 함선을 제작할 기술력은 없었죠.","JPN":"ただ、いくらアルファトリックスといえ、突然そんな艦船を作る技術力は持っていなかった。","ENG":"But even Alphatrix didn't have the tech to suddenly build a ship of that scale.","TWN":"但就算是阿爾法崔克斯，也不可能突然具備打造那種巨艦的技術。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그래서 할아버지께서는 퓨처 앳 워와 기술적 제휴를 맺으셨어요.","JPN":"だからお祖父様はフューチャーアットウォーと技術提携を結びました。","ENG":"So my grandfather entered a technical partnership with Future-at-War.","TWN":"所以祖父與天啟兵器簽訂技術合作。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"바로 이곳에서 파괴된 <color=#ffd34c>오비탈 베이스</color>의 제작을 위해서.","JPN":"他でもない、ここで破壊された<color=#ffd34c>オービタルベース</color>を作るために。","ENG":"To build the <color=#ffd34c>Orbital Base</color> that was later destroyed here.","TWN":"就是為了在這裡打造破壞的<color=#ffd34c>軌道基地</color>。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……그렇지 않나요, <color=#ffd34c>엠버</color> 박사님?","JPN":"……そうですよね？　<color=#ffd34c>アンバー</color>博士。","ENG":"...Isn't that right, Dr. <color=#ffd34c>Ember</color>?","TWN":"……不是嗎，<color=#ffd34c>琥珀</color>博士？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그렇군…….","JPN":"そうか……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_28"},{"id":"L29_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"허수 공간에서 일부러 통신 채널을 개방했던 건, 내 본체의 위치를 역추적하기 위함이었나?","JPN":"虚数空間でわざわざ通信チャンネルを開放したのは、私の本体を逆追跡するためだったのか？","ENG":"You deliberately opened a comms channel in the imaginary space to back-trace the location of my core body.","TWN":"故意在量子空間開放通訊頻道，是為了反追蹤我本體的位置嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"여기까지 계산해 두다니, 역시 빈틈이 없군. 알파트릭스 회장이 남긴 괴물다워.","JPN":"ここまで計算するとは隙がないな。さすがアルファトリックス会長が残した化け物だ。","ENG":"To have calculated this far... no loose ends indeed. Fitting for the monster Alphatrix's late President left behind.","TWN":"能預先算到這一步，果然無懈可擊。不愧是阿爾法崔克斯會長留下的怪物。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저는 이미 그룹의 회장직을 계승했답니다.","JPN":"私はすでに会長職を継承していますよ。","ENG":"I have already inherited that position.","TWN":"我已經繼承了集團的會長職位。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후후, 그래도 괴물이라 불리는 건, 역시 서운하네요.","JPN":"ふふ……でも化け物だと呼ばれるのは、やはり悲しいですね。","ENG":"Haha, still, being called a \\"monster\\" does sting a little.","TWN":"呵呵，但被稱作怪物，還是有點委屈呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"아무것도 느끼지 못하는 주제에, 인간인 척 행세하는 건가?","JPN":"何も感じない作り物の器で、人間ぶるつもりか？","ENG":"You feel nothing, yet you pretend to be human?","TWN":"你明明什麼都感覺不到，現在是在扮演人類嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 왜냐하면 저는 인간이니까요.","JPN":"はい、なぜなら私は人間ですから。","ENG":"Yes, because I am human.","TWN":"對，因為我本來就是人類。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 그건 당신도 마찬가지라고 생각해요, 엠버 박사님.","JPN":"それはあなたも同じだと思いますよ、アンバー博士。","ENG":"And I think that applies to you as well, Dr. Ember.","TWN":"而且我認為這點妳也一樣，琥珀博士。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"착각하지 마라. 인간 시절의 나약한 육체와 이름은 이미 버린 지 오래다.","JPN":"思い違いにも甚だしい。人間だった頃の脆弱な肉体と名前はとうに捨てた。","ENG":"Do not delude yourself. I discarded that frail human body and name long ago.","TWN":"妳別誤會了。我早就放棄人類時期那軟弱的軀體與名字。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_28"},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 인간은 실패로부터 깨닫고, 현실을 바꿀 힘을 가지고 있는 걸요.","JPN":"でも人間は失敗から学び、現実を変える力を持っています。","ENG":"Yet humans learn from failure and have the power to change reality.","TWN":"但人類會從失敗中領悟，進而擁有改變現實的力量。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그건 사장님도, 저도, 그리고 당신도 마찬가지죠.","JPN":"それは社長も、私も、あなたも同じ。","ENG":"That is true for Boss, for me, and for you.","TWN":"這點不只是老闆，我，還有你都一樣。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"인간이기 위해서, 이름과 겉모습 같은 건 중요하지 않다고 생각해요.","JPN":"人間であるために、名前や見た目は関係ないと思います。","ENG":"To be human, names and outer forms don't matter.","TWN":"為了做個真正的人類，我認為名字和外表這些並不重要。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"중요한 건… 그래요, <color=#ffd34c>마음</color>이죠.","JPN":"大事なのは……そう、<color=#ffd34c>心</color>です。","ENG":"What matters is... Yes, the <color=#ffd34c>heart</color>.","TWN":"重要的是……沒錯，是<color=#ffd34c>心</color>。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"마음……?","JPN":"心……？","ENG":"The heart...?","TWN":"心……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"실패에 굴하지 않고, <color=#ffd34c>더 나은 세상을 위해</color> 스스로 나아가려는 의지.","JPN":"失敗しても屈せず、<color=#ffd34c>より良い世界のために</color>前へ進もうとする意志。","ENG":"The will to keep moving forward <color=#ffd34c>for a better world</color> without bowing to failure.","TWN":"不因失敗屈服，為了<color=#ffd34c>更好的未來</color>勇於前進的意志。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저는 그게 제 마음의 형태라고 정의했어요.","JPN":"私は、それが自分の心の形だと定義しました。","ENG":"That is how I define the shape of my heart.","TWN":"我把這定義為我自己內心的形態。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"과거, 당신이 어떤 실수를 저질렀고, 어째서 그런 모습이 되었는지는 모르겠지만.","JPN":"過去にあなたがどんな間違いを犯したのか、なぜそのような姿になったのかは分かりませんが。","ENG":"I do not know what mistake you made in the past, or why you became like this.","TWN":"雖然我不清楚過去你犯了什麼錯、為什麼會變成那副模樣。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"과거의 약점을 극복하고, 진화를 멈추지 않으려는 그 알고리즘이야 말로…….","JPN":"過去の弱点を乗り越え、進化し続けようとするそのアルゴリズムこそ……","ENG":"But that algorithm which strives to overcome past weakness and never cease evolving...","TWN":"但克服過去的弱點、持續進化的演算法……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"당신을 한층 더 인간답게 만들어주는 마음이라고 할 수 있지 않을까요?","JPN":"あなたをより一層人間らしくする心だと言えるんじゃないでしょうか？","ENG":"Couldn't that be the heart that makes you more human?","TWN":"才是讓你更像人類的心吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"……자기변호에서 파생된 역겨운 궤변이로군, 괴물.","JPN":"……自己弁護から派生した、反吐が出るような詭弁だな、化け物。","ENG":"...A disgusting sophistry born from self-justification, monster.","TWN":"……原來是從自我辯護派生出的噁心謬論啊，怪物。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후후, 맞아요. 그럴지도 모르죠.","JPN":"ふふ、そうですね。そうかもしれません。","ENG":"Haha, yes. Perhaps you are right.","TWN":" 呵呵，是啊，說不定就是如此。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 괜찮아요. 저는 정말로 그렇게 믿고 있는걸요?","JPN":"それでもいいんです。私は本当にそう信じていますから。","ENG":"But it's okay. Because I truly believe it.","TWN":"不過沒關係，我真的如此相信。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"네놈이 뭐라고 지껄이든 관심 없다.","JPN":"お前が何と言おうが興味はない。","ENG":"I don't care what drivel you spew.","TWN":"你說什麼我都不在乎。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_28"},{"id":"L14_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 이 몸의 진화를 방해할 셈이라면, 이 자리에서 밑거름으로 삼아주지.","JPN":"だが私の進化を邪魔するなら、この場でお前もその進化の糧としてやろう。","ENG":"But if you intend to hinder my evolution, I will turn you into the very foundation of it here and now.","TWN":"但若妨礙我的進化，那我就會在這裡把妳當作養分。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아니요, 그 반대랍니다. 박사님.","JPN":"いいえ、逆ですよ。博士。","ENG":"No, the opposite, Doctor.","TWN":"不，正好相反，博士。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"반대라고?","JPN":"逆だと？","ENG":"The opposite?","TWN":"相反？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니, 이쪽이에요.","JPN":"ホノカさん、こちらです。","ENG":"Jin, this way.","TWN":"李珍姊姊，這邊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"지아 회장님, 정말 진심이십니까?","JPN":"会長、本気ですか？","ENG":"President Jia, are you serious?","TWN":"沈佳會長，您是認真的嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"게임에서 오비탈 베이스가 파괴된 것만으로도 그룹은 막대한 손실을 떠안았습니다.","JPN":"ゲームの際にオービタルベースが破壊されたせいで、グループは莫大な損失を抱えています。","ENG":"Even the destruction of the Orbital Base in the game saddled the group with immense losses.","TWN":"光是遊戲中軌道基地被摧毀，集團就承受了巨大的損失。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그런데 이제는 그 핵심 설비까지 이볼브 원에게 넘기시겠다니요.","JPN":"それなのに、核心設備までイボルブ・ワンに引き渡すなんて。","ENG":"And now you would hand over its core facilities to the Evolved One?","TWN":"而現在，您竟然要把核心設備交給特種艦乘務員。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"녀석은 관리국 연합 함대를 여럿 침몰시킨 괴물이지 않습니까?","JPN":"やつは管理局連合艦隊を幾度となく撃墜した化け物ではありませんか。","ENG":"That thing sank multiple Administration alliance fleets. She is a monster.","TWN":"它可是曾擊沉多艘管理局聯合艦隊的怪物吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후후, 괜찮아요. 이진 언니.","JPN":"ふふ、大丈夫です。ホノカさん。","ENG":"Haha, it's all right, Jin.","TWN":"呵呵，沒關係，李珍姊姊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"박사님이니까 넘길 수 있는 거예요.","JPN":"博士だからこそ、渡せるのです。","ENG":"Because it is the Doctor. We can trust her.","TWN":"因為是博士，所以我可以算了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"박사님이라고요……?","JPN":"博士……？","ENG":"The Doctor...?","TWN":"博士……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"후우, 회장님께선 또 영문을 알 수 없는 이야기를 하시는군요…….","JPN":"ふう……会長はまたわけの分からない話を……","ENG":"*Sigh* Once again, I can't make sense of your words...","TWN":"唉，會長又說些令人費解的話了……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그룹은 게임에 간섭한 대가로 관리국의 감사를 받게 될 거예요.","JPN":"我がグループはゲームに干渉した代償として、管理局から監査を受けることになります。","ENG":"The group will face an audit from the Administration for meddling with the game.","TWN":"集團因為干涉遊戲，將受到管理局的審查。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아무리 알파트릭스 그룹이라고 해도, 관리국이 작정한다면 한동안 움직일 수 없겠죠.","JPN":"いくらアルファトリックスグループといえども、管理局が本気を出せばしばらくは動けないでしょう。","ENG":"Even Alphatrix will be unable to move for a while if the Administration bears down.","TWN":"就算是阿爾法崔克斯集團，管理局一旦行動，也會在一段時間內動彈不得。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아마도 사건을 무마하기 위해서는 불법적인 로비나 뇌물이 필요할지도 몰라요.","JPN":"事件を揉み消すためには、違法的なロビー活動をするか、賄賂を渡す必要があるかもしれません。","ENG":"We might even need illegal lobbying or bribes to smooth things over.","TWN":"為了平息事件，恐怕還需要非法關說或賄賂。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨…….","JPN":"お嬢様……","ENG":"Miss Jia...","TWN":"小姐……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 박사님이라면 관리국의 감시를 피해, 팩토리 쉽을 재생시킬 수 있을 거예요.","JPN":"ですが博士なら管理局の監視をすり抜けて、ファクトリーシップを再生できます。","ENG":"But if it is the Doctor, you can evade their surveillance and restore the Factory Ship.","TWN":"但如果是博士，就能避開管理局監視，重建工廠艦。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 그 방법이 알파트릭스 그룹…….","JPN":"そして、それがアルファトリックスグループ……","ENG":"And that way, Alphatrix Group–","TWN":"而這個方法，就是阿爾法崔克斯集團……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아니, 결과적으로 인류가 가장 빨리 전력을 회복할 수 있는 방법이 되겠죠.","JPN":"いいえ、ひいては人類が最も早く戦力を回復できる手段になるでしょう。","ENG":"No, ultimately, this is how humanity can recover its strength the quickest","TWN":"不，結果會成為人類最快恢復戰力的方法。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"우습군, 괴물.","JPN":"笑わせてくれるな、化け物。","ENG":"Don't make me laugh, monster.","TWN":"真可笑，怪物。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"이곳에서 오비탈 베이스의 파츠를 흡수하여 전부 내 것으로 만든다고 하더라도.","JPN":"ここでオービタルベースのパーツを取り込み、すべてを私のものにしたとて……","ENG":"Even if I absorb all the Orbital Base parts here and make them mine,","TWN":"就算在這裡吸收所有軌道基地的零件變成我的，"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그 힘은 오롯이 내 것이다. 인류를 위해 쓸 이유 따윈 없어.","JPN":"その力は私だけのものだ。人類のために使う理由などない。","ENG":"the power is mine alone. I have no reason to use it for humanity.","TWN":"也只是我的力量而已，沒有要給人類使用的理由。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후후, 글쎄요.","JPN":"ふふ、どうでしょう。","ENG":"Haha, we will see.","TWN":"呵呵，是啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어쩌면 그거야말로 박사님의 마음 먹기에 따라 다르지 않을까요?","JPN":"それこそ、博士の心次第……ではないでしょうか？","ENG":"Perhaps that depends entirely on what is in your heart, Doctor.","TWN":"說不定，這正是要看博士內心想法的問題呢？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 클리포트 게임에서 파괴된 오비탈 베이스를 벌써 재건했다고?","JPN":"待って、クリフォトゲームで破壊されたオービタルベースをもう再建した？","ENG":"Hold on, you already rebuilt the Orbital Base that was destroyed in the Qliphoth Game?","TWN":"等等，妳說已經重建在逆卡巴拉遊戲中被摧毀的軌道基地了？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"파괴된 팩토리 쉽을 이 짧은 시간에…….","JPN":"破壊されたファクトリーシップをそんな短時間で……","ENG":"And the destroyed Factory Ship in such short time...","TWN":"被摧毀的工廠艦在這麼短的時間內重建……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그 정도 기술력을 가지고 있다면… 정말 가능할지도 몰라…….","JPN":"それほどの技術力があるなら……本当にいけるかもしれない……","ENG":"If you have that level of tech... it might really be possible...","TWN":"如果真的擁有ˋ這種技術能力……說不定可行……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그게 지금 아마니 벨리 쪽에 와 있단 말이야?","JPN":"それが今、アマニーバレーに来てるってこと？","ENG":"And it is near Amani Valley right now?","TWN":"它現在大概在阿馬尼峽谷吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"왜 그 사실을 지금에야 들은 거지?","JPN":"なんでそれを今まで知らなかったんだろう？","ENG":"Why am I only now hearing about this?","TWN":"為什麼我現在才聽說這件事？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"몇 시간 전에 최고 관리자님께서 긴급 차원 도약 신호가 올 수 있다고 귀띔해 주셨습니다.","JPN":"数時間前、緊急次元跳躍の信号があるかもしれないという情報を、最高管理者様が予め教えてくださったのです。","ENG":"A few hours ago, the Supreme Administrator hinted that an emergency dimension jump signal could arrive.","TWN":"幾個小時前，最高管理者提醒我可能會收到緊急跨次元信號。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님이 아라크네를 개조하시던 그 시간에 말이죠.","JPN":"ちょうどシニア様がアラクネを改造されていた頃ですね。","ENG":"Right around when you were modifying the Arachne, Senior.","TWN":"就在Senior改造阿拉克涅的那段時間。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흠, 흠! 아무튼, 평생 한번 볼까말까한 팩토리 쉽이 로터스에 와 있다는 소리잖아?","JPN":"ご、ごほん！　とにかく、あの一生に一度見れるかどうかっていうファクトリーシップがロータスに来てるってことでしょ？","ENG":"Ahem! Anyway, that means a once-in-a-lifetime Factory Ship is in Lotus, right?","TWN":" 嗯、嗯！總之這就表示這輩子難得一見的工廠艦已經來到洛德斯了？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"맞아요.","JPN":"そうです。","ENG":"That's correct.","TWN":"沒錯。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그렇다는 건…….","JPN":"ってことは……","ENG":"Which means...","TWN":"這也代表……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"우리 계획은 실패할 수 없다는 소리죠.","JPN":"私たちの計画は決して失敗しないということです。","ENG":"Our plan cannot fail.","TWN":"我們的計畫不能失敗。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"팩토리 쉽이라면 분명 빠르게 선로전환기를 제작할 수 있겠지…….","JPN":"ファクトリーシップなら、きっと素早く線路転換器を製作できる……","ENG":"With the Factory Ship, we can fast-track the production of the Track Switchers...","TWN":"只要有工廠艦，就能快速製作線路轉換器……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"무엇보다, 제가 직접 시스템을 운용할 계획이니까요.","JPN":"何より、私が直接システムを運用する予定ですから。","ENG":"Above all, I plan to run the system myself.","TWN":"最重要的是我將親自操作系統。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"설계도만 제공해 주신다면 다른 작업은 제가 해결할 거예요.","JPN":"設計図さえご提供いただければ、他の作業は私の方で処理します。","ENG":"If you provide the blueprints, I will handle the rest.","TWN":"只要您提供設計圖，其他的工作就交給我來處理。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"……응.","JPN":"……うん。","ENG":"...Okay.","TWN":"……嗯。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이게 설계도로군요.","JPN":"これが設計図なのですね。","ENG":"These are the blueprints, I presume.","TWN":"這就是設計圖啊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"좋아요. 이 정도면 몇 시간 내에 시제품을 제작해 시험해 볼 수 있겠네요.","JPN":"いいでしょう。これなら数時間内に試作品を完成させ、テストできそうです。","ENG":"Good. With this, we can fabricate a prototype and test it within hours.","TWN":"好。這個程度的話，幾個小時內就能做出樣品測試了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐? 그게 끝이야?","JPN":"え？　それだけで？","ENG":"Huh? That's it?","TWN":"什麼？這樣就結束了？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"시니어님이 우려하시는 점은 바로 차원 좌표를 강제로 변경시키는 장치일 거예요.","JPN":"シニアが心配されているのは、次元座標を強制的に変更させる装置の部分でしょう。","ENG":"What worries you is a device that forcibly alters dimension coordinates.","TWN":"Senior擔心的應該是那個強行改變次元座標的裝置吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"반대쪽에서 부상하는 차원 도약체를 관측하고 그 순간 똑같은 힘으로 되받아치는 장치인 것 같은데,","JPN":"反対側から浮上する次元跳躍体を観測し、同時に同じ力で受け返す装置のようですが……","ENG":"It seems to observe an incoming dimensional jumping object on the other side and counter it with equal force at that instant,","TWN":"那個看起來是能在另一側偵測升起的次元跳躍體，並在那瞬間以同等力量反擊的裝置。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"단 한 치의 오차도 없는 정확도와 정밀도가 필요한 작업이죠.","JPN":"ほんの少しの誤差も許されない、正確さと精密さが求められる作業ですね。","ENG":"which requires absolute accuracy and precision with not even a hair's breadth of error.","TWN":"這也是一個需要零誤差精準度與細密度的作業。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"……맞아.","JPN":"……そうなの。","ENG":"...Right.","TWN":"……沒錯。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"게다가 막대한 출력이 필요하기 때문에 각종 안정기의 성능도 확인해야 할걸?","JPN":"それに、莫大な出力が必要だから、各種安定器の性能も確かめないといけないよ？","ENG":"And because it needs massive output, we must validate the stabilizers' performance.","TWN":"再加上需要龐大的輸出，所以也得確認各種穩定器的性能吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 부분에 대해서도 제가 해결할 수 있어요.","JPN":"それについても私の方で解決できます。","ENG":"I can handle that part as well.","TWN":"那部分我也能解決。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"시니어님의 설계대로라면 특정 부분들은 이터니움 합금이 아닌 티타늄으로 이루어져 있더라고요.","JPN":"シニアの設計だと、特定部分はエタニウム合金ではなくチタニウムになっていますね。","ENG":"Per your design, certain sections are titanium instead of Eternium alloy.","TWN":"依照Senior的設計，某些地方不是用永恆之金合金，而是使用鈦合金呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이건 에너지가 과 방출될 시 티타늄이 변형되어 안정기를 활성화시키는 원리죠?","JPN":"これはエネルギーが放出されすぎた時にチタニウムが変形し、安定器を活性化させる仕組みだからですよね？","ENG":"When energy over-discharges, the titanium deforms and triggers the stabilizer, correct?","TWN":"這是因為當能量過度釋放時，鈦金屬會產生形變，從而啟動穩定器的原理對吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 이 증폭기의 경우엔…….","JPN":"そしてこの増幅器は……","ENG":"And in the case of this amplifier...","TWN":"還有這個增幅器……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이터니움 활성화 에너지가 안정화되면 증폭 렌즈를 통해 증폭 및 집중을 시켜야 해.","JPN":"エタニウム活性化エネルギーが安定化したら、増幅レンズで増幅・集中させないといけない。","ENG":"Once Eternium activation energy stabilizes, we must amplify and focus it through an amplification lens.","TWN":"永恆之金的活化能量穩定後，必須透過增幅透鏡放大與集中。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그러니 미세한 오차조차 용납할 수 없는 두께로 깎아내야 하겠죠? 잘 알겠어요.","JPN":"だから少しの誤差もない厚さに加工する必要がありますね。分かりました。","ENG":"Which means the thickness must be shaved to a tolerance where even micro-errors are unacceptable, correct? Understood.","TWN":"所以得削到連微細誤差都不容許的厚度對吧？我知道了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"알파트릭스 회장이 괴물이라 불릴 정도의 천재라더니…….","JPN":"アルファトリックスの会長は、化け物と呼ばれるほどの天才だと聞いたけど……","ENG":"So the Alphatrix President is a genius worthy of being called a monster...","TWN":"聽說阿爾法崔克斯會長是聰明到被稱為怪物的程度……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당신, 말이 좀 잘 통하네.","JPN":"あなた、話が通じる人じゃない。","ENG":"You and I speak the same language, it seems.","TWN":"你挺好溝通的嘛。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후훗, 저도 이렇게 완벽한 설계 도면을 보는 건 오랜만이네요.","JPN":"ふふっ、私もここまで完璧な設計図を目にするのは久しぶりです。","ENG":"Haha, it has been a while since I saw a blueprint this perfect.","TWN":" 呵呵，我也好久沒看到這麼完美的設計圖了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이렇게 재밌게 이야기를 나눠본 건 사장님 이후로는 거의 처음이거든요.","JPN":"こんなに楽しくお話できたのは、社長の時以来初めてかもしれません。","ENG":"The last time I had this much fun talking shop was with Boss.","TWN":"好像是繼老闆之後第一次能這麼愉快地聊天呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 당신이라면 믿고 맡길 수 있겠어.","JPN":"よし。あなたになら、信じて任せられるよ。","ENG":"All right. I can trust you with this.","TWN":"好。如果是你，我可以放心交給你。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"대신, 한 가지 부탁이 있어!","JPN":"その代わりに、1つ頼みがあるの！","ENG":"In exchange, I have one request!","TWN":"但我要拜託你一件事！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"말씀만 하세요. 사장님의 친구는 제 친구이기도 하니까요.","JPN":"何でもどうぞ。社長のお友達は私の友達でもありますもの。","ENG":"Name it. A friend of Boss is my friend too.","TWN":"您請說吧。老闆的朋友，也是我的朋友。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이번 소동이 마무리되면…….","JPN":"今回の騒ぎが落ち着いたら……","ENG":"Once this whole mess is over...","TWN":"這次騷動結束後……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"팩토리 쉽을 견학해볼 수 있을까?!","JPN":"ファクトリーシップを見学してもいい！？","ENG":"Can I tour the Factory Ship?!","TWN":"我可以去參觀一下工廠艦嗎？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"응? 그럴 수 있지?","JPN":"ね？　いいよね？","ENG":"Mm? That can be arranged, right?","TWN":"嗯？當然可以啊？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그렇지????","JPN":"いいよね？？","ENG":"Right???","TWN":"對吧？？？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"후후후후…….","JPN":"ふふふふ……","ENG":"He he he he...","TWN":"呵呵呵呵……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"기분이 좋아 보이시는 군요.","JPN":"機嫌が良さそうですね。","ENG":"You look to be in high spirits.","TWN":"您看起來心情很好耶。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 기분이 좋기는.","JPN":"ふん、そんなことないけど。","ENG":"Hmph, hardly.","TWN":"哼，我才沒有呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그렇다기엔 입가에 미소가 지워지질 않습니다만.","JPN":"その割には口元が緩んでいますが。","ENG":"Funny how that smile has not left your face.","TWN":"可是你嘴角的微笑沒有消失耶。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흠, 흠!","JPN":"ゴホン、ゴホン！","ENG":"Ahem. Ahem!","TWN":" 咳、咳！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"알파트릭스의 팩토리 쉽은 도시 관리국 규모의 생산 시설이나 다름없다고.","JPN":"アルファトリックスのファクトリーシップは、都市管理局規模の生産施設に他ならない。","ENG":"Alphatrix's Factory Ship is practically a City Management-scale production facility.","TWN":"阿爾法崔克斯的工廠艦，規模和城市管理局的生產設施差不多。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그런 기술의 집약체를 직접 견학할 수 있게 되었는데 설렐 수밖에 없잖아.","JPN":"そんな技術のかたまりのようなものを見学できるんだから、浮かれて当然でしょ。","ENG":"How could I not be excited getting to tour that pinnacle of engineering in person?","TWN":"聽到能參觀那種技術結晶，叫我不興奮也難。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"물론… 살아남아야 가능한 이야기겠지만 말이야.","JPN":"まあ……生き残れたらの話だけど。","ENG":"Of course, that only happens if we survive.","TWN":"當然……前提是要活著才有機會。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"현재 우리 쪽 상황은 어때?","JPN":"今、こっちの状況はどう？","ENG":"What's our current status?","TWN":"現在我們狀況怎麼樣？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"현재, 대균열은 불규칙한 속도로 확장하고 있습니다.","JPN":"現在、大亀裂は不規則な速度で拡張しています。","ENG":"Currently, the Grand Dimension Crevice is expanding at irregular speed.","TWN":"目前大峽谷正以不規律的速度擴大。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그 여파로 도시 각 구역에 CSE 레벨은 상승 중.","JPN":"その影響で、都市の各区域のCSEレベルは上昇中。","ENG":"As a result, CSE levels are rising across city sectors.","TWN":"餘波動讓城市各區的CSE等級上升中。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시민들의 대피를 돕고 있지만 침식체들로 인해 그마저도 여의치 않은 상황입니다.","JPN":"市民の避難を支援してはいますが、侵食体のせいでそれもなかなか難しい状況です。","ENG":"We are assisting evacuations, but C.O.s are making even that difficult.","TWN":"儘管我們正在協助市民撤離，但受到侵蝕體的干擾，情況並不樂觀。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"으음… 병력을 더 동원할 수는 없을까?","JPN":"うーん……兵力をもっと増やせないかな？","ENG":"Hmm... Can we deploy more forces?","TWN":"嗯……不能再動員更多兵力嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이미 긴급 소집 명령도 마친 상태입니다.","JPN":"すでに緊急招集命令も出しています。","ENG":"Emergency muster orders have already gone out.","TWN":"已經下達緊急召集命令了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이대로 의미 없는 소모전만 계속된다면, 분명 관리국은 물론, 시민들도 지키지 못할 겁니다.","JPN":"このまま無意味な消耗戦が続くと、管理局はもちろん、市民たちを守ることすらかなわないでしょう。","ENG":"If we keep bleeding in a futile war of attrition, we will fail to protect both the Administration and the citizens.","TWN":"如果無意義的消耗戰再這樣持續下去，不只管理局，我們連市民都守不住。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이졸데 양은 청사진도 없이 다이브 항법장치의 역설계를 통해 그 모방품을 만들어낼 만큼 아주 대단한 천재지.","JPN":"イゾルデ君は青写真がなくてもダイブ航法装置の逆設計を通じてその模倣品を作り上げるほどにとても優れた天才だ。","ENG":"Isolde is a genius who reverse-engineered the dive navigation device and built a replica of it without a blueprint.","TWN":"伊索德小姐是能在沒有藍圖的情況下，透過反向解析跳躍導航裝置製作複製品的天才。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀를 시니어로 세운 것은 그 재능을 높이 샀기 때문일세.","JPN":"彼女をシニアとして立てたのは、その才能を高く評価したからだよ。","ENG":"I appointed her as Senior because I highly valued her talent.","TWN":"我就是因為看中了她的才能才讓她成為Senior。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오늘 내가 이곳에 온 건, 자네의 그 재능이 필요해서야.","JPN":"今日私がここに来たのは、君のその才能が必要だからだ。","ENG":"And I am here today because I need your talents.","TWN":"我今天來到這裡，就是需要你的那個才能。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그럼 우선 계속 밀리기만 하는 상황을 타파… 해야겠지.......","JPN":"じゃあ、押されるばかりのこの状況を……どうにかしないとね……","ENG":"Then first, we need to put an end... to this constant retreat...","TWN":"那麼我們首先得突破……不斷節節敗退的局勢才行……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"파티마, 그… 우리 쪽에서 방어에 유리한 구역을 위주로… 방위선을 세울 수 있을까?","JPN":"ファティマ、その……ロータス側から防衛に有利な区域を中心に……防衛線を張れるかな？","ENG":"Fatima, um... do you think we could set up our defense line around the areas that favor us?","TWN":"法蒂瑪，那個……能以對我們有利的區域為中心……建立一道防線嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이졸데 양은 인정 욕구도 많지만, 그에 따른 책임감 또한 훌륭하다고 생각했네.","JPN":"イゾルデ君は承認欲求も強いが、それに伴う立派な責任感の持ち主だと思っている。","ENG":"Isolde craves recognition, yet her sense of responsibility matches it.","TWN":"伊索德小姐雖然好勝心強，但我認為她也有優秀的責任感。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 시니어 자리에 앉힌 건 잘한 결정이야.","JPN":"やはりシニアの座に就かせたのは、正しい判断だったな。","ENG":"Appointing her as a Senior was the right call.","TWN":"讓她坐上Senior的位置果然是正確的決定。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"히이익!","JPN":"ひいいっ！","ENG":"Eeek!","TWN":"嗚哇！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"다, 당신! 도대체 언제부터 통신을 듣고 있던 거야?!","JPN":"あ、あなた！　いつから通信を聞いてたの！？","ENG":"Y-you! How long have you been listening in?!","TWN":"你、你！到底從什麼時候開始竊聽通信的？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 연락했을 때부터 지금까지 끊은 적이 없네만.","JPN":"君が連絡した時から今まで、繋ぎっぱなしだったのだが。","ENG":"Since you contacted me. I haven't hung up.","TWN":"從妳聯絡我開始就沒斷過啊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아, 지아양이 흔쾌히 견학을 허락했을 때 자네가 춤을 추며 불렀던 콧노래가…….","JPN":"ああ、ユイ君が快く見学を承諾した時に君が踊りながら歌った鼻歌は……","ENG":"Ah, and when Jia gladly approved your tour, the little tune you hummed as you danced–","TWN":"啊，當沈佳小姐答應讓妳參觀，妳邊跳舞邊哼的小調……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아아아아아아악!","JPN":"ああああああっ！","ENG":"AAAAAAAH!","TWN":"啊啊啊啊啊啊！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그만 끊어! 당신도 당신 일로 바쁠 것 아냐?!","JPN":"もう切って！　あなたも自分の仕事で忙しいでしょ！？","ENG":"Hang up already! You must be busy with your work too!","TWN":"快關掉！你也該忙你的事了吧？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이졸데 양의 감미로운 노래 정도는 들을 시간이…….","JPN":"イゾルデ君の素敵な歌を聞く時間ぐらい十分……","ENG":"I have time to listen to your sweet singing...","TWN":"我還是有時間聽伊索德小姐甜美的歌聲……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"최고 관리자님의 칭찬을 들을 기회를 이렇게 날려버리다니.","JPN":"最高管理者様に褒められるチャンスを逃すなんて。","ENG":"You just threw away a chance to hear the Supreme Administrator's praise.","TWN":"妳居然就這樣放飛得到最高管理者稱讚的機會。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"무례하시군요.","JPN":"失礼ですね。","ENG":"How discourteous.","TWN":"真失禮。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"시끄러워! 무례한 건 너지!","JPN":"うるさい！　失礼なのはファティマのほうよ！","ENG":"Quiet! You're the rude one!","TWN":"吵死了！失禮的是你吧！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"네 직속상관은 저 사람이 아니라 나라고! 나!","JPN":"あなたの上司はあの人じゃなくて私だからね！","ENG":"Your superior is not him, it is me! ME!","TWN":"你的直屬上司不是那個人，是我！是我！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"으으…… 저 사람이랑 엮이면 내가 바보가 되는 것 같다니까.","JPN":"うう……あの人と関わると自分がバカになる気がする。","ENG":"Uuugh... Whenever I deal with that man, I feel like he makes me look foolish.","TWN":"唉……只要扯上跟那個人，我都變笨了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그래도 긴장은 좀 풀리시지 않았습니까?","JPN":"そう言われましても、緊張は大分ほぐれたのでは？","ENG":"Still, you do seem a little less tense now.","TWN":"不過你現在多少放鬆一點了吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"……흥.","JPN":"……ふん。","ENG":"...Hmph.","TWN":"……哼。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래서 내가 방금 얘기한 방위선 구축에 대해 어떻게 생각해?","JPN":"で、さっき私が言った防衛線の件はどう思う？","ENG":"So, what do you think of the defense line I just proposed?","TWN":"所以我剛說的那道防線，你覺得怎麼樣？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"속절없이 밀려나는 것보단 조금이라도 버텨보는 편이 좋겠죠.","JPN":"成すすべもなく押されるばかりよりは、少しでも粘ったほうがいいでしょう。","ENG":"It is better to hold even a little than to be pushed back without a fight.","TWN":"比起被打到不能還手，多少抵抗一下比較好吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"꽤 좋은 의견을 제안하셨군요.","JPN":"かなりいい意見だったと思います。","ENG":"That is a solid proposal.","TWN":"妳的建議挺不錯的呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그, 그래?","JPN":"そ、そう？","ENG":"R-really?","TWN":"真、真的嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그럼 어디서부터 시작해야 할까?","JPN":"じゃあどこから始めたらいいかな？","ENG":"Then where should we start?","TWN":"那從哪裡開始著手比較好？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그… 행정적인 부분은 아무래도 내가 좀 모자라니까.","JPN":"その……行政的な部分は、やっぱり私、未熟だから。","ENG":"I am... not great on the administrative side.","TWN":"那個……行政方面我不太能處理。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"우선, 시민들이 무사히 재건 도시로 대피할 수 있도록 공항, 항구, 격납고 쪽을 확보해야 합니다.","JPN":"まず、市民たちが再建都市に無事避難できるよう、空港・港・格納庫を確保する必要があります。","ENG":"First, secure airports, harbors, and hangars so citizens can evacuate safely to the Rebuilt Cities.","TWN":"首先為了讓市民能安全撤往重建城市，要優先確保機場、港口、機庫。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"사막에선 차원 폭풍이, 바다에선 침식체들의 활동이 감지되고 있지만… 여기서 개죽음당하는 것보단 나을 겁니다.","JPN":"砂漠からは次元の暴風が、海からは侵食体の活動が確認されていますが……ここで犬死にするよりはマシでしょう。","ENG":"There are dimensional storms in the desert and C.O. activity at sea... but it is better than dying here for nothing.","TWN":"沙漠那邊偵測到次元風暴，海上又有侵蝕體活動……但總比白白死在這裡好。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"재건 도시의 수용량도 고려해야 합니다.","JPN":"再建都市が受容できる人数も考慮しないといけません。","ENG":"We must also consider the capacity of the Rebuilt Cities.","TWN":"我們還必須考量重建城市的收容量。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그건… 시니어님의 소극적인 성격으론 부탁하기 어려울 테니 제가 월권을 좀 해보죠.","JPN":"それは……消極的なシニア様の性格では頼みづらいと思うので、越権行為をさせていただきます。","ENG":"Your... reserved personality makes it hard to ask, so I will overstep a little and handle the negotiations.","TWN":"那部分……Senior的個性有點消極，應該不好意思開口，所以我會越權處理。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"고, 고마워.","JPN":"あ、ありがとう。","ENG":"Th-thanks.","TWN":"謝、謝謝。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"지금 대균열의 영향을 받는 도시가… ARC-EA2, 구 아스완이지?","JPN":"今大亀裂の影響を受けてる都市は……ARC-EA2、旧アスワンだよね？","ENG":"The city currently affected by the Grand Dimension Crevice is... ARC-EA2, the former Aswan, right?","TWN":"現在受大峽谷影響的城市……是ARC-EA2，也就是舊阿斯旺對吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"방위선은 구축하는데 얼마나 걸릴 것 같아?","JPN":"防衛線の構築にはどれぐらいかかりそう？","ENG":"How long to set up the defense line?","TWN":"完成防線大概要花多久時間？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"EA2는 강이 인접한 도시입니다.","JPN":"EA2は川に隣接した都市です。","ENG":"EA2 is a riverside city.","TWN":"EA2是鄰近河流的城市。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시민들을 항구 쪽으로 대피시킨다면 대피 작업은 비교적 수월할지도 모릅니다.","JPN":"市民を港方面に誘導すれば、避難作業は比較的スムーズに進むかもしれません。","ENG":"If we evacuate citizens toward the port, the operation might go relatively smoothly.","TWN":"如果將市民往港口方向疏散，撤離工作可能會比較順利。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그쪽부터 시작하면 되겠습니까?","JPN":"そちらから始めましょうか？","ENG":"Shall we begin there?","TWN":"可以從那裡開始嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"응. 그렇게 해줘.","JPN":"うん、そうして。","ENG":"Okay, let's do that.","TWN":"嗯，就這樣進行吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그리고 그곳에는 이터니움 보관소가 위치하고 있습니다.","JPN":"そして、あそこにはエタニウム保管所があります。","ENG":"There is also an Eternium depot there.","TWN":"還有，永恆之金保管所也在那裡。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그곳이 점령당하면 이터니움을 촉매로 더 강한 침식체가 부상할 가능성이 있죠.","JPN":"あそこを占領されると、エタニウムを触媒としてより強い侵食体が浮上する恐れがあります。","ENG":"If it falls, stronger C.O.s may emerge using Eternium as a catalyst.","TWN":"那裡若被佔領，可能會使用永恆之金作為催化劑，出現更強的侵蝕體。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"시민들이 대피를 1순위로, 이터니움 보관소를 2순위로 보호해.","JPN":"市民の避難を最優先に、エタニウム保管所の防衛をその次にして。","ENG":"Put citizen evacuation first priority, the Eternium depot second.","TWN":"撤離市民是第一順位，接下來是保護永恆之金保管所。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"각 도시에 보관해 둔 이터니움들은 선로전환기에 쓰일 귀중한 자원들이야.","JPN":"各都市に保管しておいたエタニウムは、線路転換器を稼働させる貴重な資源になる。","ENG":"The Eternium stored in each city is a precious resource for the Track Switcher.","TWN":"各城市存放的永恆之金是用於線路轉換器的重要資源。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"방위선을 구축하는 한편, 이터니움을 확보하도록 해줘.","JPN":"防衛線の構築と同時に、エタニウムの確保もお願い。","ENG":"While establishing the line, secure the Eternium.","TWN":"建立防線的同時，也要確保永恆之金的安全。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"……알겠습니다.","JPN":"……承知しました。","ENG":"...Understood.","TWN":"……我知道了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"드디어 시니어라는 직책에 책임감이라는 것을 느끼기 시작하신 모양이군요.","JPN":"やっと、シニアという役職の責任を感じ始めたようですね。","ENG":"It seems you are finally feeling what responsibility means for a Senior.","TWN":"看來您終於開始體會Senior這個職位的責任了呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"원래라면…….","JPN":"いつもなら……","ENG":"Normally...","TWN":"若是以前……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"원래라면 무서워서 어디 구석에라도 숨었겠지. 늘 그랬으니까.","JPN":"いつもなら怖くてどこかに隠れてたよね。いつもそうしてたし。","ENG":"Normally, I would be too scared and hide in a corner somewhere. Like always.","TWN":"若是以前，我一定會嚇得躲到某個角落。一直以來我都是如此。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하지만 관리국 직할 도시의 총책임자가 나서지 않으면 사람들이 뭐라고 생각하겠어?","JPN":"でも管理局直轄都市の総責任者が前に出ないと、みんな納得できないでしょ。","ENG":"But if the director of an Administration Direct Control City doesn't step up, what'll the people think?","TWN":"但如果管理局直轄城市的總負責人不挺身而出，大家又會怎麼想呢？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"사람들 앞에 서는 건 무섭고…… 부끄럽고…… 위험하지만…….","JPN":"人前に立つのは怖いし……恥ずかしいし……危ないけど……","ENG":"Standing before people is scary... embarrassing... and dangerous...","TWN":"雖然站在眾人面前很可怕……很害羞……也很危險……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나서야 할 때 나서야 이 자리를 맡긴 최고 관리자의 얼굴도 똑바로 볼 수 있겠지.","JPN":"出る時は出ないと、私をこの座に就かせた最高管理者に向ける顔がないよ。","ENG":"But stepping up when I must is the only way I can face the Supreme Administrator who entrusted me with this seat.","TWN":"但在必須站出來的時候挺身而出，才有臉面對把這個位置交給我的最高管理者吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"それに……","ENG":"And...","TWN":"而且……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"날 인정해 준 그 사람이 이 자리에 있었다면…… 그렇게 했을 테니까.","JPN":"私を認めてくれたあの人が、もしここに立っていたら……そうしたはずだから。","ENG":"If the one who acknowledged me were here... that is what he would do.","TWN":"如果那個認可我的人在這裡……一定也會這麼做。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};